private void xrTableCell44_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

// Get current row values
decimal pol = Convert.ToDecimal(GetCurrentColumnValue("POL"));
decimal countFlock = Convert.ToDecimal(GetCurrentColumnValue("CountFlock"));

if (countFlock > 0)
{
    cell.Text = (pol / countFlock).ToString("0.##");
}
else
{
    cell.Text = "0";
}

}

