private void xrTableCell18_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
 XRTableCell cell = sender as XRTableCell;

// Get values from the data source
decimal femaleStarted = Convert.ToDecimal(GetCurrentColumnValue("Female_Started") ?? 0);
decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("Female_Mort") ?? 0);
decimal femaleCK = Convert.ToDecimal(GetCurrentColumnValue("Female_CK") ?? 0);
decimal femaleCS = Convert.ToDecimal(GetCurrentColumnValue("Female_CS") ?? 0);

if (femaleStarted > 0)
{
    // Calculate: (Female_Mort + Female_CK + Female_CS) / Female_Started * 100
    decimal totalRemovals = femaleMort + femaleCK + femaleCS;
    decimal result = (totalRemovals / femaleStarted) * 100.0m;
    cell.Text = result.ToString("N2"); // Formats to 2 decimal places
}
else
{
    cell.Text = "0.00";
}
}

