private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     decimal pol = Convert.ToDecimal(GetCurrentColumnValue("POL") ?? 0);
        decimal floorEggs = Convert.ToDecimal(GetCurrentColumnValue("FloorEggs") ?? 0);
        decimal nestedEggs = Convert.ToDecimal(GetCurrentColumnValue("NestedEggs") ?? 0);

        if (pol > 0)
        {
            decimal ratio = (floorEggs + nestedEggs) / pol;
            totalRatio += ratio;
            validRowCount++;
        }
    // Calculate Ratio 2: (HatchingEggs + HatchingFloorG_A + HatchingFloorG_B) / POL
        if (pol > 0)
        {
            decimal hatchingEggs = Convert.ToDecimal(GetCurrentColumnValue("HatchingEggs") ?? 0);
            decimal hatchingFloorG_A = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_A") ?? 0);
            decimal hatchingFloorG_B = Convert.ToDecimal(GetCurrentColumnValue("HatchingFloorG_B") ?? 0);

            decimal ratio2 = (hatchingEggs + hatchingFloorG_A + hatchingFloorG_B) / pol;
            totalRatio2 += ratio2;
            validRowCount2++;
        }
         // --- Ratio 3: ((Female_Mort + Female_CK + Female_CS) / Female_Started) * 100 ---
        if (femaleStarted > 0)
        {
            decimal femaleMort = Convert.ToDecimal(GetCurrentColumnValue("Female_Mort") ?? 0);
            decimal femaleCK = Convert.ToDecimal(GetCurrentColumnValue("Female_CK") ?? 0);
            decimal femaleCS = Convert.ToDecimal(GetCurrentColumnValue("Female_CS") ?? 0);

            decimal ratio3 = ((femaleMort + femaleCK + femaleCS) / femaleStarted) * 100;
            totalRatio3 += ratio3;
            validRowCount3++;
        }
        // --- Ratio 4: ((DeadChicks + Culls + Chicks) / SettingEggs) * 100 ---
        if (settingEggs > 0)
        {
            decimal deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks") ?? 0);
            decimal culls = Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);
            decimal chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks") ?? 0);

            decimal ratio4 = ((deadChicks + culls + chicks) / settingEggs) * 100;
            totalRatio4 += ratio4;
            validRowCount4++;
        }
        // --- Ratio 5: (DeadChicks + Culls + Chicks) / POL ---
        if (pol > 0)
        {
            decimal deadChicks = Convert.ToDecimal(GetCurrentColumnValue("DeadChicks") ?? 0);
            decimal culls = Convert.ToDecimal(GetCurrentColumnValue("Culls") ?? 0);
            decimal chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks") ?? 0);

            decimal ratio5 = (deadChicks + culls + chicks) / pol;
            totalRatio5 += ratio5;
            validRowCount5++;
        }
}

